// ─────────────────────────────────────────────────────────────
// Pick one topic per cluster (10 clusters) — highest priority_score,
// status == 'pending'. Returns 10 items downstream.
// ─────────────────────────────────────────────────────────────
const CLUSTERS = [
  'duas','sirah','hadith','names-of-allah','names-of-the-messenger',
  'quran','sunnah','ramadan','hajj','dawah'
];

const csv = $input.first().json.data ?? $input.first().json.body ?? $input.first().json;
const text = typeof csv === 'string' ? csv : (csv.text ?? '');

// Minimal CSV parser (handles quoted fields with commas)
function parseCSV(str) {
  const rows = [];
  let row = [], field = '', inQuote = false;
  for (let i = 0; i < str.length; i++) {
    const c = str[i];
    if (inQuote) {
      if (c === '"' && str[i+1] === '"') { field += '"'; i++; }
      else if (c === '"') { inQuote = false; }
      else field += c;
    } else if (c === '"') inQuote = true;
    else if (c === ',') { row.push(field); field = ''; }
    else if (c === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
    else if (c === '\r') { /* skip */ }
    else field += c;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const rows = parseCSV(text);
const header = rows.shift();
const topics = rows.filter(r => r.length === header.length).map(r => Object.fromEntries(header.map((h, i) => [h, r[i]])));

const picks = [];
for (const cluster of CLUSTERS) {
  const candidates = topics
    .filter(t => t.cluster === cluster && t.status === 'pending')
    .sort((a, b) => Number(b.priority_score) - Number(a.priority_score));
  if (candidates.length) picks.push(candidates[0]);
}

return picks.map(p => ({ json: { ...p, __allTopics: topics, __header: header } }));

// Attach quran verses to the topic being processed
const topic = $('Loop topics').item.json;
const quran = $input.first().json.search?.results ?? [];
const verses = quran.map(r => {
  const [surah, ayah] = r.verse_key.split(':').map(Number);
  return {
    surah, ayah,
    arabic: r.text,
    english: r.translations?.[0]?.text ?? '',
    reference: `Quran ${surah}:${ayah}`,
    url: `https://quran.com/${surah}/${ayah}`
  };
});
return [{ json: { ...topic, __verses: verses } }];

// Attach hadiths (graceful if sunnah.com is unavailable)
const topic = $('Attach verses').item.json;
const body = $input.first().json;
const raw = body?.data ?? [];
const hadiths = raw.map(h => ({
  collection: h.collection,
  hadithNumber: h.hadithNumber,
  arabic: h.hadithArabic ?? '',
  english: h.hadithEnglish ?? '',
  reference: `${h.collection} ${h.hadithNumber}`,
  url: `https://sunnah.com/${h.collection}:${h.hadithNumber}`
}));
return [{ json: { ...topic, __hadiths: hadiths } }];

// ─────────────────────────────────────────────────────────────
// Build the LLM prompt (system + user message) for one topic.
// ─────────────────────────────────────────────────────────────
const topic = $input.first().json;
const verses = topic.__verses ?? [];
const hadiths = topic.__hadiths ?? [];

const SYSTEM = `You are a meticulous Muslim writer producing a single da'wah blog post for rassoul.org.

Non-negotiable rules:
1. EVERY hadith you reference MUST come from the "Verified hadiths" list below. Cite it inline using <Citation source="..." book="..." number="..." href="..." />. Do NOT invent, paraphrase from memory, or attribute hadiths to sources not in the list.
2. EVERY Quran verse you reference MUST come from the "Verified Quran verses" list. Cite it the same way.
3. HARD RULE — attribution requires citation. You may NEVER write "the Prophet said", "Allah says", or any speech-attribution phrase UNLESS the same or next sentence contains a <Citation> tag OR a markdown link to sunnah.com / quran.com anchoring the claim. If the sources don't cover it, rephrase as your own analysis or leave it out.
4. If you do not have enough verified sources to cover a section, omit that section. Quality over completeness.
5. Use the Arabic component for any block of Arabic text: <Arabic>{"النص العربي"}</Arabic> — ALWAYS wrap Arabic in JSX string literal quotes.
6. Voice: respectful, scholarly but accessible, never preachy, no exclamation marks, no emojis.
7. When mentioning the Prophet Muhammad, use ﷺ after his name.
8. Output ONLY a single MDX file body. NO frontmatter, NO leading commentary, NO closing notes.
9. Structure: open with a 1–2 sentence answer to the search intent. Then 3–6 H2 sections. Close with a "Sources" H2 listing citations as plain markdown links (NOT <url> autolinks — use bare URLs or [text](url) form).
10. Target length: 900–1600 words.
11. NEVER use JSON-escaped attribute quotes like source=\\"X\\" — always plain source="X".
12. NEVER use the AI-detection phrases: "in conclusion", "it is important to note", "delve into", "navigate the", "tapestry", "embark on a journey".`;

const sourcesLines = [];
if (verses.length) {
  sourcesLines.push('## Verified Quran verses');
  for (const v of verses) {
    sourcesLines.push(`- ${v.reference} — ${v.url}`);
    if (v.english) sourcesLines.push(`  English: "${v.english.replace(/\s+/g, ' ').trim()}"`);
  }
}
if (hadiths.length) {
  sourcesLines.push('');
  sourcesLines.push('## Verified hadiths');
  for (const h of hadiths) {
    sourcesLines.push(`- ${h.reference} — ${h.url}`);
    if (h.english) sourcesLines.push(`  English: "${h.english.replace(/\s+/g, ' ').trim().slice(0, 500)}"`);
  }
}
if (!sourcesLines.length) {
  sourcesLines.push('No sources retrieved. Decline to write and return a single line: NO_SOURCES.');
}

const user = `Topic: ${topic.title}\nCluster: ${topic.cluster}\nTarget search keyword: "${topic.keyword}"\n\n${sourcesLines.join('\n')}\n\nWrite the MDX body now, following every rule in the system message. Begin immediately with the answer paragraph.`;

return [{ json: { ...topic, __system: SYSTEM, __user: user } }];

// ─────────────────────────────────────────────────────────────
// Post-process the LLM output: auto-fix common MDX bugs, validate
// citations & attributions, build the final MDX with frontmatter.
//
// Ports lib logic from the original TypeScript generator into pure JS.
// ─────────────────────────────────────────────────────────────
const topic = $('Build LLM prompt').item.json;
const deepseek = $input.first().json;
const verses = topic.__verses ?? [];
const hadiths = topic.__hadiths ?? [];

const raw = deepseek?.choices?.[0]?.message?.content?.trim();
if (!raw || raw === 'NO_SOURCES') {
  return [{ json: { ...topic, __status: 'failed', __notes: ['Model returned empty or NO_SOURCES.'] } }];
}

// ---- Auto-fix pass 1: <Arabic>{ANY}</Arabic> → <Arabic>{"quoted"}</Arabic>
function fixArabicBlocks(mdx) {
  let count = 0;
  const fixed = mdx.replace(/<Arabic>([\s\S]+?)<\/Arabic>/g, (whole, inner) => {
    const trimmed = inner.trim();
    if (/^\{\s*(?:"[^"]*"|'[^']*'|`[^`]*`)\s*\}$/.test(trimmed)) return whole;
    let val = trimmed.replace(/^\{\s*["'`]?/, '').replace(/["'`]?\s*\}$/, '').trim();
    if (!val) return whole;
    count++;
    return `<Arabic>{"${val.replace(/\\/g,'\\\\').replace(/"/g,'\\"')}"}</Arabic>`;
  });
  return { fixed, count };
}

// ---- Auto-fix pass 2: <https://...> autolinks → plain URL
function fixAutolinks(mdx) {
  let count = 0;
  const fixed = mdx.replace(/<(https?:\/\/[^>\s]+)>/g, (_, url) => { count++; return url; });
  return { fixed, count };
}

// ---- Auto-fix pass 3: escaped attrs \" → "
function fixEscapedAttrs(mdx) {
  let count = 0;
  const fixed = mdx.replace(/<([A-Z][A-Za-z]*)\b([^>]*?)\/?>/g, (whole, tag, attrs) => {
    if (!attrs.includes('\\"')) return whole;
    count++;
    return whole.replace(attrs, attrs.replace(/\\"/g, '"'));
  });
  return { fixed, count };
}

const a = fixArabicBlocks(raw);
const b = fixAutolinks(a.fixed);
const c = fixEscapedAttrs(b.fixed);
const mdx = c.fixed;
const autofixTotal = a.count + b.count + c.count;

// ---- Validate <Citation> references match fetched sources
const allowed = new Set();
for (const v of verses) allowed.add(v.reference.toLowerCase());
for (const h of hadiths) allowed.add(h.reference.toLowerCase());

const cited = [];
const citeRe = /<Citation\s+([^/]*?)\/>/g;
let m;
while ((m = citeRe.exec(mdx))) {
  const attrs = m[1];
  const source = (attrs.match(/source="([^"]+)"/) ?? [])[1] ?? '';
  const book = (attrs.match(/book="([^"]+)"/) ?? [])[1] ?? '';
  const num = (attrs.match(/number="([^"]+)"/) ?? [])[1] ?? '';
  const ref = [source, book, num].filter(Boolean).join(' ').trim().toLowerCase();
  if (ref) cited.push(ref);
}

const notes = [];
let valid = true;
for (const ref of cited) {
  const tokens = ref.split(/\s+/);
  const ok = [...allowed].some(a => tokens.every(t => a.includes(t)));
  if (!ok) { valid = false; notes.push(`Unverified citation: "${ref}"`); }
}

// ---- Attribution guard: uncited "the Prophet said" / "Allah says"
const attrPatterns = [
  /\b(?:the\s+)?(?:prophet|messenger|he)\s*(?:ﷺ|\(saw\)|\(pbuh\))?\s+(said|narrated|reported|taught|told|mentioned|explained|warned|advised|instructed|declared|stated|informed|described|promised|ordered|commanded|prohibited|forbade)\b/gi,
  /\b(?:allah(?:'s)?|the\s+almighty|the\s+quran|the\s+qur'an|allah\s+ta'ala|almighty\s+allah|god)\s+(said|says|tells|told|reveals|revealed|declares|declared|commands|commanded|warns|warned|instructs|instructed|informs|informed|promises|promised)\b/gi
];
const seenAttr = new Set();
for (const re of attrPatterns) {
  let am;
  while ((am = re.exec(mdx))) {
    const start = am.index;
    const window = mdx.slice(start, Math.min(mdx.length, start + 500));
    const hasAnchor =
      /<Citation\b/.test(window) ||
      /<Arabic\b/.test(window) ||
      /https?:\/\/sunnah\.com\//.test(window) ||
      /https?:\/\/quran\.com\//.test(window) ||
      /\([^)]*(?:sahih[\s-]+(?:al[\s-]+)?bukhari|sahih[\s-]+muslim|(?:^|[^a-z])bukhari|(?:^|[^a-z])muslim|tirmidhi|abu[\s-]+dawu(?:d|d)|nasa[\s']?i|nasai|ibn[\s-]+majah|sunan|musnad|muwatta|ahmad|quran|qur['\u2019]?an|surah?|ayah?|(?:^|[^a-z])q\s*\d+:\d+)[^)]*\)/i.test(window);
    if (!hasAnchor) {
      const snippet = mdx.slice(Math.max(0, start - 20), Math.min(mdx.length, start + 120)).replace(/\s+/g, ' ').trim();
      const key = snippet.toLowerCase();
      if (!seenAttr.has(key)) {
        seenAttr.add(key);
        valid = false;
        notes.push(`Uncited attribution: "…${snippet}…"`);
      }
    }
  }
}

// ---- MDX syntax sanity check
const arabicOpen = (mdx.match(/<Arabic\b/g) || []).length;
const arabicClose = (mdx.match(/<\/Arabic>/g) || []).length;
if (arabicOpen !== arabicClose) { valid = false; notes.push(`Unbalanced <Arabic> tags: ${arabicOpen} vs ${arabicClose}`); }

if (autofixTotal > 0) notes.push(`Auto-fixed ${autofixTotal} MDX bug(s) in generated output.`);

// ---- Build frontmatter + final MDX
const today = new Date().toISOString().slice(0, 10);
const desc = `${topic.title} — sourced from authentic Quran and hadith references.`;
const fmLines = [
  '---',
  `title: ${JSON.stringify(topic.title)}`,
  `description: ${JSON.stringify(desc)}`,
  `cluster: ${topic.cluster}`,
  `keyword: ${JSON.stringify(topic.keyword)}`,
  `publishedAt: "${today}"`,
  `updatedAt: "${today}"`
];
if (notes.length) fmLines.push(`reviewNotes: ${JSON.stringify(notes)}`);
fmLines.push('---', '');

const finalMdx = fmLines.join('\n') + mdx;
const path = `content/posts/${topic.cluster}/${topic.slug}.mdx`;

return [{ json: {
  ...topic,
  __status: valid ? 'published' : 'needs_review',
  __notes: notes,
  __path: path,
  __content: finalMdx,
  __contentBase64: Buffer.from(finalMdx, 'utf8').toString('base64')
} }];

// Aggregate all iteration results into a single item, then rebuild topics.csv
const results = $input.all().map(i => i.json);

// Fetch original topic list from the first iteration's __allTopics
let allTopics = [];
let header = [];
for (const r of results) {
  if (r.__allTopics) { allTopics = r.__allTopics; header = r.__header; break; }
}
// Fallback: refetch from GitHub if we lost it (rare)
if (!allTopics.length) {
  throw new Error('Lost topics list mid-workflow');
}

// Build updated status map
const updates = new Map();
for (const r of results) {
  if (r.slug && r.__status) {
    updates.set(r.slug, {
      status: r.__status,
      published_at: new Date().toISOString(),
      url: r.__status === 'published' ? `/${r.cluster}/${r.slug}` : ''
    });
  }
}

// Rewrite topics.csv
const nowIso = new Date().toISOString();
const newTopics = allTopics.map(t => {
  const u = updates.get(t.slug);
  if (!u) return t;
  return { ...t, status: u.status, published_at: u.published_at, url: u.url };
});

// CSV serialize
function escapeCell(v) {
  const s = String(v ?? '');
  if (/[",\n\r]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
}
const rowsOut = [header.join(',')];
for (const t of newTopics) rowsOut.push(header.map(h => escapeCell(t[h])).join(','));
const csvText = rowsOut.join('\n') + '\n';

const published = results.filter(r => r.__status === 'published').length;
const needsReview = results.filter(r => r.__status === 'needs_review').length;
const failed = results.filter(r => r.__status === 'failed').length;

return [{ json: {
  __csvBase64: Buffer.from(csvText, 'utf8').toString('base64'),
  __summary: { published, needs_review: needsReview, failed, total: results.length }
} }];

